/**
 * 50 high-intent SEO blog topics + 10 full long-form blog posts (1200+ words).
 *
 * These are DISTINCT from existing topics in:
 *   - blog-topic-clusters.ts (115 topics)
 *   - conversion-blog-posts.ts (20 topics)
 *   - market-blog-posts.ts (13 posts)
 *
 * Markets: Philippines (10), India (10), Nigeria (10), Kenya (5), Canada RPN (10), UK (5)
 * All English. All conversion-focused. All with internal links + CTAs + APA references.
 *
 * Route: /en/{{region}}/{{profession}}/{{exam}}/blog/{{slug}}
 */

import type { GlobalRegionSlug, GlobalLocaleCode } from "@/lib/i18n/global-regions";

// ── Types ────────────────────────────────────────────────────────────────────

export type LongFormBlogSection = {
  heading: string;
  body: string;
};

export type LongFormFaqItem = {
  question: string;
  answer: string;
};

export type LongFormReference = {
  text: string;
};

export type LongFormBlogTopic = {
  id: string;
  region: GlobalRegionSlug;
  locale: GlobalLocaleCode;
  profession: string;
  exam: string;
  title: string;
  metaTitle: string;
  metaDescription: string;
  slug: string;
  primaryKeyword: string;
  searchIntent: "transactional" | "informational" | "comparison";
};

export type LongFormBlogPost = LongFormBlogTopic & {
  wordCount: number;
  sections: LongFormBlogSection[];
  faq: LongFormFaqItem[];
  references: LongFormReference[];
};

// ── Link helper ──────────────────────────────────────────────────────────────

function L(region: string, prof: string, exam: string) {
  const base = `/en/${region}/${prof}/${exam}`;
  return {
    lessons: `${base}/lessons`,
    questions: `${base}/questions`,
    cat: `${base}/cat`,
    pricing: `${base}/pricing`,
    lesson: (slug: string) => `${base}/lessons/${slug}`,
  };
}

